import { useEffect, useState } from 'react'
import { doc, onSnapshot } from 'firebase/firestore'
import { db, DEMO_MODE } from '../firebase'
import OctopusMark from './OctopusMark'

const DEMO_LINE = 'שלושה ניחושי 1-0 ברצף? אפילו אני, תמנון, מצפה לקצת דרמה. תרימו את הראש (וגם את התוצאות)! 🐙'

/** סטורי התמנון's daily AI one-liner (generated by the pundit workflow). */
export default function PunditCard() {
  const [text, setText] = useState<string>(DEMO_MODE ? DEMO_LINE : '')

  useEffect(() => {
    if (DEMO_MODE) return
    return onSnapshot(doc(db, 'appState', 'pundit'), (s) => setText((s.data()?.text as string) || ''))
  }, [])

  if (!text) return null
  return (
    <div className="glass" style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '12px 16px', background: 'linear-gradient(135deg, color-mix(in srgb, var(--color-primary) 12%, var(--color-bg-elevated)), var(--color-bg-elevated))' }}>
      <OctopusMark size={40} />
      <div>
        <div style={{ fontSize: 11, color: 'var(--color-text-muted)', fontWeight: 700 }}>סטורי התמנון אומר</div>
        <div style={{ fontWeight: 600, fontSize: 14, lineHeight: 1.5 }}>{text}</div>
      </div>
    </div>
  )
}
